@auto_docstring
class Qwen3Model(Qwen3PreTrainedModel):
    def __init__(self, config: Qwen3Config,engram_config: Optional[EngramConfig] = None):
        """
        Initializes a Qwen3Model with Engram module integration.

        Args:
            config (`Qwen3Config`):
                Base configuration object for the Qwen3 model, containing core parameters such as hidden size,
                number of attention heads, number of layers, vocab size, RoPE settings, and sliding window config.
            engram_config (`EngramConfig`):
                Configuration for the Engram module integration, including the layer IDs where Engram should be injected,
                tokenizer path for n-gram processing, n-gram size settings, embedding dimensions, and other Engram-specific
                hyperparameters. This config determines which layers will have Engram functionality enabled.
        """
        super().__init__(config)
        self.padding_idx = config.pad_token_id
        self.vocab_size = config.vocab_size
        self.engram_config = engram_config

        self.engram_layer_ids = (
            list(engram_config.layer_ids) if engram_config is not None and hasattr(engram_config, "layer_ids") else []
        )
        self.embed_tokens = nn.Embedding(config.vocab_size, config.hidden_size, self.padding_idx)
        self.layers = nn.ModuleList(
            [Qwen3DecoderLayerWithEngram(
                config, 
                layer_idx,
                engram_config=engram_config,
                engram_layer_ids=self.engram_layer_ids)
                for layer_idx in range(config.num_hidden_layers)]
        )
        # 最终归一化层 norm
        self.norm = Qwen3RMSNorm(config.hidden_size, eps=config.rms_norm_eps)
        # 生成 Qwen3 专属的旋转位置编码（RoPE）的 cos/sin 旋转因子
        self.rotary_emb = Qwen3RotaryEmbedding(config=config)
        self.gradient_checkpointing = False
        self.has_sliding_layers = "sliding_attention" in self.config.layer_types

        # Initialize weights and apply final processing
        # 执行模型权重的标准化初始化和最终处理
        self.post_init()

    # @check_model_inputs：输入校验装饰器，自动检查输入参数的合法性
    @check_model_inputs
    @auto_docstring
    def forward(
        self,
        input_ids: torch.LongTensor | None = None,
        attention_mask: torch.Tensor | None = None,
        position_ids: torch.LongTensor | None = None,       # 位置索引张量，形状为(batch_size, seq_len)
        past_key_values: Cache | None = None,               # KV 缓存对象（DynamicCache），存储历史 K/V 特征
        inputs_embeds: torch.FloatTensor | None = None,
        cache_position: torch.LongTensor | None = None,     # 缓存位置索引
        use_cache: bool | None = None,                      
        is_first_iteration: bool | None = False,
        **kwargs: Unpack[TransformersKwargs],
    ) -> BaseModelOutputWithPast:                           # 带 KV 缓存的自回归模型设计

        engram_outputs_list: List[torch.Tensor] = []  # 存储各Engram层的output
        engram_gates_list: List[torch.Tensor] = []    # 存储各Engram层的gate
        engram_embeddings_list: List[torch.Tensor] = []  # 存储各Engram层的拼接embedding
        engram_layer_mapping: Dict[int, int] = {}  # 图层ID → 输出列表索引的映射

        # 异或校验，确保input_ids和inputs_embeds恰好指定其中一个
        if (input_ids is None) ^ (inputs_embeds is not None):
            raise ValueError("You must specify exactly one of input_ids or inputs_embeds")

        if inputs_embeds is None:
            inputs_embeds = self.embed_tokens(input_ids)
        # 为自回归推理初始化动态 KV 缓存
        if use_cache and past_key_values is None:
            past_key_values = DynamicCache(config=self.config)
        # 生成当前序列在历史缓存中的位置索引，是RoPE 位置编码和KV 缓存更新的核心依据，
        # 解决自回归推理中「历史序列 + 当前序列」的位置对齐问题
        # past_key_values 会完整缓存所有历史序列的 K/V 特征
        if cache_position is None:
            past_seen_tokens = past_key_values.get_seq_length() if past_key_values is not None else 0
            # 从序列起始（第 0 个 token）开始、覆盖「历史缓存的所有 token + 当前输入的新 token」的全局连续位置编号
            cache_position = torch.arange(
                past_seen_tokens, past_seen_tokens + inputs_embeds.shape[1], device=inputs_embeds.device
            )
        # cache_position [S,] → unsqueeze(0) → position_ids [1, S]
        if position_ids is None:
            position_ids = cache_position.unsqueeze(0)

        # It may already have been prepared by e.g. `generate`
        # 若传入的attention_mask不是字典（如训练 / 首次推理时），则进入掩码生成流程
        causal_mask_mapping = attention_mask
        if not isinstance(causal_mask_mapping, dict):
            # Prepare mask arguments
            # 整理掩码生成所需的参数
            mask_kwargs = {
                "config": self.config,
                "input_embeds": inputs_embeds,
                "attention_mask": attention_mask,       # 基础PAD掩码
                "cache_position": cache_position,       # 全局连续位置索引（历史+当前）
                "past_key_values": past_key_values,     
                "position_ids": position_ids,           # 位置索引（辅助掩码生成）
            }
            # Create the masks
            causal_mask_mapping = {
                "full_attention": create_causal_mask(**mask_kwargs),
            }
            # The sliding window alternating layers are not always activated depending on the config
            # 按需生成滑动窗口掩码
            if self.has_sliding_layers:
                causal_mask_mapping["sliding_attention"] = create_sliding_window_causal_mask(**mask_kwargs)

        hidden_states = inputs_embeds
        # 生成全局 RoPE 旋转位置编码因子
        position_embeddings = self.rotary_emb(hidden_states, position_ids)
       

        for layer_idx, decoder_layer in enumerate(self.layers[: self.config.num_hidden_layers]):
            hidden_states,engram_outputs,engram_gates,engram_embeddings = decoder_layer(
                hidden_states,
                attention_mask=causal_mask_mapping[decoder_layer.attention_type],
                position_embeddings=position_embeddings,    # RoPE 旋转位置编码因子
                position_ids=position_ids,
                past_key_values=past_key_values,
                use_cache=use_cache,
                cache_position=cache_position,
                input_ids=input_ids,
                is_first_iteration=is_first_iteration,
                **kwargs,
            )

            if layer_idx in self.engram_layer_ids:
                engram_outputs_list.append(engram_outputs)
                engram_gates_list.append(engram_gates)
                engram_embeddings_list.append(engram_embeddings)
                engram_layer_mapping[layer_idx] = len(engram_outputs_list) - 1


        hidden_states = self.norm(hidden_states)
        
        # 返回值是 Hugging Face Transformers 库专为带 KV 缓存的自回归模型设计的标准化输出类实例
        # 可直接被generate文本生成、Trainer训练器、下游任务头解析
        output =Qwen3ModelOutputWithPast(
            last_hidden_state=hidden_states,
            past_key_values=past_key_values if use_cache else None,
            engram_outputs=engram_outputs_list,
            engram_gates=engram_gates_list,
            engram_embeddings=engram_embeddings_list,
            engram_layer_mapping=engram_layer_mapping,
        )

        return output
@auto_docstring
# 继承自顶层预训练基类 Qwen3PreTrainedModel 和生成能力 Mixin GenerationMixin
class Qwen3ForCausalLM(Qwen3PreTrainedModel, GenerationMixin):
    # 指定词嵌入层与语言模型头的权重共享规则，输出与输入嵌入权重相同
    _tied_weights_keys = {"lm_head.weight": "model.embed_tokens.weight"}
    # 张量并行：指定lm_head层在张量并行时的输出聚合方式为按列聚合，会将 vocab_size 维度拆分到不同卡上
    _tp_plan = {"lm_head": "colwise_gather_output"}
    # Pipeline Parallel（流水线并行）：指定lm_head层在流水线并行时的输入输出映射关系
    _pp_plan = {"lm_head": (["hidden_states"], ["logits"])}

    def __init__(self, config,engram_config: Optional[EngramConfig] = None):
        """
        Initializes a Qwen3ForCausalLM model with Engram module integration.

        Args:
            config (`Qwen3Config`):
                Base configuration object for Qwen3 model, containing all the core parameters (hidden size,
                number of layers, vocab size, etc.).
            engram_config (`EngramConfig`):
                Configuration for the Engram module, which specifies the layers to inject Engram, tokenizer path,
                n-gram settings, and other Engram-specific hyperparameters. This config is passed to the underlying
                Qwen3Model to enable Engram functionality.
        """
        super().__init__(config)
        self.model = Qwen3Model(config, engram_config)
        self.vocab_size = config.vocab_size
        self.lm_head = nn.Linear(config.hidden_size, config.vocab_size, bias=False)
        self.engram_config = engram_config

        # Initialize weights and apply final processing
        # 执行模型权重的标准化初始化和最终处理
        self.post_init()

         # 重要：self.post_init() 会按 Qwen 默认规则初始化新增模块，
        # 会覆盖 Engram 自定义初始化（如 xavier/自定义 std）。
        # 这里显式回填 Engram 的初始化，保证插件参数分布符合预期。
        self._reset_engram_parameters()
    def _reset_engram_parameters(self):
        """Restore Engram-specific initialization after HF post_init."""
        for layer in self.model.layers:
            if getattr(layer, "engram", None) is None:
                continue
            layer.engram._init_engram()
            layer.engram.multi_head_embedding._init_embedding()
            layer.engram.short_conv._init_conv()

    def reset_engram_inference_cache(self):
        """
        在一轮新生成开始前重置所有 Engram 层的推理缓存，避免跨样本污染。
        """
        for layer in self.model.layers:
            engram = getattr(layer, "engram", None)
            if engram is None:
                continue
            if hasattr(engram, "reset_inference_cache"):
                engram.reset_inference_cache()

    def attach_engram(self, engram_config: EngramConfig, init_weights: bool = True):
        self.engram_config = engram_config
        self.model.engram_config = engram_config
        self.model.engram_layer_ids = list(engram_config.layer_ids)

        for layer_id in self.model.engram_layer_ids:
            layer = self.model.layers[layer_id]
            if getattr(layer, "engram", None) is None:
                ref_device = layer.input_layernorm.weight.device
                layer.engram = Engram(layer_id, config=engram_config).to(device=ref_device)
        
        if init_weights:
            self._reset_engram_parameters()

    @classmethod
    def from_pretrained(
        cls,
        pretrained_model_name_or_path: str,
        *model_args,
        engram_config=None,  # 单独声明 engram_config 参数
        **kwargs,
    ):
        engram_config = kwargs.pop("engram_config", engram_config)
        model_args = list(model_args)
        model_args.insert(0, engram_config)
        
        # 调用父类 from_pretrained
        model = super().from_pretrained(pretrained_model_name_or_path, *model_args, **kwargs)
        
        # 只需绑定配置（Engram 已在 Qwen3Model.__init__ 中初始化）
        if engram_config is not None:
            model.engram_config = engram_config
        
        return model

    @can_return_tuple
    @auto_docstring
    def forward(
        self,
        input_ids: torch.LongTensor | None = None,
        attention_mask: torch.Tensor | None = None,
        position_ids: torch.LongTensor | None = None,
        past_key_values: Cache | None = None,
        inputs_embeds: torch.FloatTensor | None = None,
        labels: torch.LongTensor | None = None,             # 训练时传入，与 input_ids 对应，用于计算损失，给出正确答案的索引
        use_cache: bool | None = None,
        cache_position: torch.LongTensor | None = None,
        logits_to_keep: int | torch.Tensor = 0,
        is_first_iteration: bool | None = False,
        **kwargs: Unpack[TransformersKwargs],
    ) -> CausalLMOutputWithPast:
        r"""
        labels (`torch.LongTensor` of shape `(batch_size, sequence_length)`, *optional*):
            Labels for computing the masked language modeling loss. Indices should either be in `[0, ...,
            config.vocab_size]` or -100 (see `input_ids` docstring). Tokens with indices set to `-100` are ignored
            (masked), the loss is only computed for the tokens with labels in `[0, ..., config.vocab_size]`.

        Example:

        ```python
        >>> from transformers import AutoTokenizer, Qwen3ForCausalLM

        >>> model = Qwen3ForCausalLM.from_pretrained("Qwen/Qwen3-8B")
        >>> tokenizer = AutoTokenizer.from_pretrained("Qwen/Qwen3-8B")

        >>> prompt = "Hey, are you conscious? Can you talk to me?"
        >>> inputs = tokenizer(prompt, return_tensors="pt")

        >>> # Generate
        >>> generate_ids = model.generate(inputs.input_ids, max_length=30)
        >>> tokenizer.batch_decode(generate_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
        "Hey, are you conscious? Can you talk to me?\nI'm not conscious, but I can talk to you."
        ```"""
        # 完全复用Qwen3Model的端到端特征提取能力，得到包含归一化后语义特征和KV 缓存的标准化输出
        outputs: Qwen3ModelOutputWithPast= self.model(
            input_ids=input_ids,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            use_cache=use_cache,
            cache_position=cache_position,
            is_first_iteration=is_first_iteration,
            **kwargs,
        )

        hidden_states = outputs.last_hidden_state
        # Only compute necessary logits, and do not upcast them to float if we are not computing the loss
        # 推理时切片仅对需要的部分特征计算 logits；训练时获取 logits 的张量以计算损失
        # logits_to_keep是int时，直截取一个位置的切片；是张量时，按张量索引取切片 
        slice_indices = slice(-logits_to_keep, None) if isinstance(logits_to_keep, int) else logits_to_keep
        logits = self.lm_head(hidden_states[:, slice_indices, :])
        # 按需计算训练损失
        loss = None
        if labels is not None:
            loss = self.loss_function(logits=logits, labels=labels, vocab_size=self.config.vocab_size, **kwargs)
        # Hugging Face 专为因果语言模型设计的标准化输出类实例
        return Qwen3CausalLMOutputWithPast(
            loss=loss,
            logits=logits,
            past_key_values=outputs.past_key_values,
            hidden_states=outputs.hidden_states,
            attentions=outputs.attentions,
            engram_outputs=outputs.engram_outputs,
            engram_gates=outputs.engram_gates,
            engram_embeddings=outputs.engram_embeddings,
            engram_layer_mapping=outputs.engram_layer_mapping,
        )
    
    def prepare_inputs_for_generation(
        self,
        input_ids: torch.LongTensor,
        past_key_values: Cache | None = None,
        attention_mask: torch.LongTensor | None = None,
        inputs_embeds: torch.FloatTensor | None = None,
        cache_position: torch.LongTensor | None = None,
        is_first_iteration: bool | None = False,
        **kwargs,
    ):
        model_inputs = super().prepare_inputs_for_generation(
            input_ids=input_ids,
            past_key_values=past_key_values,
            attention_mask=attention_mask,
            inputs_embeds=inputs_embeds,
            cache_position=cache_position,
            is_first_iteration=is_first_iteration,
            **kwargs,
        )

        # 新一轮generate的首步（past_key_values为空）先清空Engram缓存，
        # 防止上一条样本遗留状态带入当前样本。
        if past_key_values is None:
            self.reset_engram_inference_cache()

        model_inputs["is_first_iteration"] = is_first_iteration
        return model_inputs

    def _reorder_cache(self, past_key_values, beam_idx):
        """
        beam search 每步选枝后，除重排 self-attn KV cache 外，
        还需要同步重排 Engram 内部缓存，保证每个beam只携带自己的历史。
        """
        # 1) 先重排主干 self-attn 的 KV cache
        reordered_past = past_key_values
        if past_key_values is not None:
            if hasattr(past_key_values, "reorder_cache"):
                # 新版 Cache API（如 DynamicCache）
                past_key_values.reorder_cache(beam_idx)
                reordered_past = past_key_values
            elif isinstance(past_key_values, tuple):
                # 兼容老版 tuple KV cache
                reordered_past = tuple(
                    tuple(
                        past_state.index_select(0, beam_idx.to(past_state.device))
                        for past_state in layer_past
                    )
                    for layer_past in past_key_values
                )

        # 2) 同步重排 Engram 内部缓存
        for layer in self.model.layers:
            engram = getattr(layer, "engram", None)
            if engram is None:
                continue
            if hasattr(engram, "reorder_inference_cache"):
                engram.reorder_inference_cache(beam_idx)

        return reordered_past


@dataclass
class Qwen3ModelOutputWithPast(BaseModelOutputWithPast):
    """
    Qwen3模型输出(包含Engram层输出),继承自BaseModelOutputWithPast,完全兼容原有字段。
    
    Args:
        engram_outputs (`List[torch.FloatTensor]`, *optional*):
            各Engram层的输出列表,每个张量形状为 (batch_size, sequence_length, hidden_size)。
        engram_gates (`List[torch.FloatTensor]`, *optional*):
            各Engram层的门控值列表,每个张量形状为 (batch_size, sequence_length, 1)。
        engram_embeddings (`List[torch.FloatTensor]`, *optional*):
            各Engram层的拼接原始embedding列表,每个张量形状为 (batch_size, sequence_length, n_embed_per_ngram * (max_ngram_size - 1))。
        engram_layer_mapping (`Dict[int, int]`, *optional*):
            图层ID到输出列表索引的映射字典,格式 {layer_id: index}。
    """
    engram_outputs: Optional[List[torch.FloatTensor]] = None
    engram_gates: Optional[List[torch.FloatTensor]] = None
    engram_embeddings: Optional[List[torch.FloatTensor]] = None
    engram_layer_mapping: Optional[Dict[int, int]] = None

@dataclass
class Qwen3CausalLMOutputWithPast(CausalLMOutputWithPast):
    """
    Qwen3因果语言模型输出(包含完整Engram层输出),继承自CausalLMOutputWithPast,完全兼容原有字段。
    
    Args:
        engram_outputs (`List[torch.FloatTensor]`, *optional*):
            各Engram层的输出列表,每个张量形状为 (batch_size, sequence_length, hidden_size)。
        engram_gates (`List[torch.FloatTensor]`, *optional*):
            各Engram层的门控值列表,每个张量形状为 (batch_size, sequence_length, 1)。
        engram_embeddings (`List[torch.FloatTensor]`, *optional*):
            各Engram层的拼接原始embedding列表,每个张量形状为 (batch_size, sequence_length, n_embed_per_ngram * (max_ngram_size - 1))。
        engram_layer_mapping (`Dict[int, int]`, *optional*):
            图层ID到输出列表索引的映射字典,格式 {layer_id: index}。
    """
    engram_outputs: Optional[List[torch.FloatTensor]] = None
    engram_gates: Optional[List[torch.FloatTensor]] = None
    engram_embeddings: Optional[List[torch.FloatTensor]] = None
    engram_layer_mapping: Optional[Dict[int, int]] = None 


